<?php namespace App\Http\Middleware; use App\Models\Auth\LoginSession; use Closure; class DeviceTracking { public function handle($req, Closure $next) { $fingerprint = $req->header('X-Device-Fingerprint'); if ($fingerprint && auth()->check()) { LoginSession::create(['user_id' => auth()->id(), 'device_fingerprint' => $fingerprint, 'device_os' => $this->parseOS($req->userAgent()), 'device_browser' => $this->parseBrowser($req->userAgent()), 'ip_address' => $req->ip(), 'logged_in_at' => now(), 'last_activity_at' => now()]); } return $next($req); } private function parseOS($ua) { preg_match('/Windows|Mac|Linux/', $ua, $m); return $m[0] ?? 'Unknown'; } private function parseBrowser($ua) { preg_match('/Chrome|Firefox|Safari/', $ua, $m); return $m[0] ?? 'Unknown'; } }
